#!/usr/bin/env bash
# tails1154OS fix - unpacks updated Calamares config + first-boot script
set -euo pipefail

echo "==> Fixing tails1154OS Calamares config..."

B64=''


echo "$B64" | base64 -d | sudo tar xz -C /
sudo mkdir -p /root/Desktop

cat << 'EOF' | sudo tee /root/Desktop/calamares.desktop > /dev/null
[Desktop Entry]
Name=Install tails1154OS
Comment=Install tails1154OS to your computer
Exec=calamares
Icon=calamares
Terminal=false
Type=Application
Categories=Qt;System;
EOF

echo "==> Done! Run 'calamares' to start the installer."
